import{_ as t,o as e,c as n,ai as s}from"./chunks/framework.SowO7O0D.js";const b=JSON.parse('{"title":"第十一课：MACD指标","description":"","frontmatter":{},"headers":[],"relativePath":"guide/11-macd.md","filePath":"guide/11-macd.md","lastUpdated":0}'),r={name:"guide/11-macd.md"};function l(i,a,d,o,p,c){return e(),n("div",null,[...a[0]||(a[0]=[s(`<h1 id="第十一课-macd指标" tabindex="-1">第十一课：MACD指标 <a class="header-anchor" href="#第十一课-macd指标" aria-label="Permalink to “第十一课：MACD指标”">​</a></h1><p>MACD是技术分析中最常用的指标之一，可以帮你判断趋势的力度和方向。</p><h2 id="一、macd是什么" tabindex="-1">一、MACD是什么？ <a class="header-anchor" href="#一、macd是什么" aria-label="Permalink to “一、MACD是什么？”">​</a></h2><p>MACD = Moving Average Convergence Divergence（移动平均收敛发散指标）</p><p><strong>核心作用</strong>：判断股票趋势是走强还是走弱。</p><h2 id="二、macd的构成" tabindex="-1">二、MACD的构成 <a class="header-anchor" href="#二、macd的构成" aria-label="Permalink to “二、MACD的构成”">​</a></h2><p>MACD由<strong>三条线</strong>和一个<strong>红绿柱</strong>组成：</p><table tabindex="0"><thead><tr><th>组成部分</th><th>作用</th></tr></thead><tbody><tr><td>DIF线（快线）</td><td>短期与中期的指数均线差</td></tr><tr><td>DEA线（慢线）</td><td>DIF线的均线，更平滑</td></tr><tr><td>红绿柱</td><td>DIF与DEA的差值，表示力度</td></tr></tbody></table><blockquote><p>💡 你可以简单理解为：<strong>红柱变长 = 上涨力度增强，绿柱变长 = 下跌力度增强</strong></p></blockquote><h2 id="三、macd的核心用法" tabindex="-1">三、MACD的核心用法 <a class="header-anchor" href="#三、macd的核心用法" aria-label="Permalink to “三、MACD的核心用法”">​</a></h2><h3 id="_1-金叉与死叉" tabindex="-1">1. 金叉与死叉 <a class="header-anchor" href="#_1-金叉与死叉" aria-label="Permalink to “1. 金叉与死叉”">​</a></h3><p><strong>金叉（买入）</strong>：DIF线上穿DEA线</p><p><strong>死叉（卖出）</strong>：DIF线下穿DEA线</p><blockquote><p>💡 和均线的金叉死叉类似，但MACD更平滑，信号更可靠。</p></blockquote><h3 id="_2-零轴" tabindex="-1">2. 零轴 <a class="header-anchor" href="#_2-零轴" aria-label="Permalink to “2. 零轴”">​</a></h3><p>零轴是一条<strong>分界线</strong>：</p><table tabindex="0"><thead><tr><th>位置</th><th>含义</th></tr></thead><tbody><tr><td>DIF &gt; 0（零轴上方）</td><td>短期均线在长期均线上方，偏强</td></tr><tr><td>DIF &lt; 0（零轴下方）</td><td>短期均线在长期均线下方，偏弱</td></tr></tbody></table><p><strong>操作原则</strong>：</p><ul><li>只做零轴上方的股票（只做强势）</li><li>零轴下方的金叉，可能是弱反弹，不参与</li></ul><h3 id="_3-背离-最重要" tabindex="-1">3. 背离（最重要！） <a class="header-anchor" href="#_3-背离-最重要" aria-label="Permalink to “3. 背离（最重要！）”">​</a></h3><p><strong>顶背离</strong>：股价创新高，但MACD没有创新高 → 预警！可能要跌</p><p><strong>底背离</strong>：股价创新低，但MACD没有创新低 → 预警！可能要涨</p><blockquote><p>💡 <strong>背离是MACD最有价值的信号</strong>，但要等走出来才能确认，不能预测。</p></blockquote><h2 id="四、macd的局限性" tabindex="-1">四、MACD的局限性 <a class="header-anchor" href="#四、macd的局限性" aria-label="Permalink to “四、MACD的局限性”">​</a></h2><blockquote><p>⚠️ <strong>MACD是趋势指标，在震荡市里容易反复打脸。</strong></p></blockquote><ul><li>横盘震荡时，MACD会频繁在零轴附近交叉</li><li>MACD有滞后性，往往在行情走了一段后才出现信号</li><li><strong>不能单独用MACD</strong>，必须结合均线、K线形态、成交量</li></ul><h2 id="五、macd实战口诀" tabindex="-1">五、MACD实战口诀 <a class="header-anchor" href="#五、macd实战口诀" aria-label="Permalink to “五、MACD实战口诀”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>零轴上方金叉，强势</span></span>
<span class="line"><span>零轴下方金叉，弱势（可能只是反弹）</span></span>
<span class="line"><span>高位死叉，赶紧跑</span></span>
<span class="line"><span>低位金叉，慢慢买</span></span>
<span class="line"><span>顶背离要小心</span></span>
<span class="line"><span>底背离要留意</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某股票股价创了新高，但MACD没有创新高，形成了顶背离。你会怎么做？</p></blockquote><hr><p><strong>下一课预告</strong>：技术分析学完了，下一课学习<strong>价值投资</strong>——股神巴菲特的投资理念。</p>`,32)])])}const g=t(r,[["render",l]]);export{b as __pageData,g as default};
